<style lang="scss" scoped>
.bg-linear {
    position: relative;
    width: 100%;
    height: auto;

    &::after {
        position: absolute;
        top: 0;
        left: 0;
        content: '';
        width: 100%;
        height: 100%;
        background: linear-gradient($c-black, $c-skyblue);
        opacity: 0.75;
    }

    .container {
        width: 100%;
        height: 100vh;
        position: relative;

        .cover-image {
            width: 100%;
            height: 100vh;
            object-fit: cover;
            object-position: center;
            mask-image: linear-gradient(to bottom, rgba(0,0,0,1) 60%, rgba(0,0,0,0) 100%);
        }

        .movie-details {
            width: 1170px;
            padding: 0 15px;
            margin: 0 auto;
            position: absolute;
            z-index: 4;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);

            .movie {
                &-title {
                    color: $c-white;
                    font-size: 40px;
                    letter-spacing: 4px;
                }

                &-info-box {
                    font-size: 18px;
                    color: $c-white;
                    display: flex;
                    align-items: center;

                    .info {
                        margin: 0 30px;
                        font-weight: 700;
                        font-size: 24px;

                        svg {
                            width: 40px;
                            height: 40px;
                            margin-bottom: -8px;
                            margin-right: 5px;
                            fill: $c-white;
                        }
                    }
                }

                &-desc {
                    color: $c-white;
                    font-size: 18px;
                    text-align: justify;
                }
            }

            .btns {
                margin-left: 40px;
                display: flex;
                align-items: center;

                .btn {
                    padding: 16px 24px;
                    color: $c-dark-theme;
                    margin: 0 20px;
                    font-size: 18px;
                    border-radius: 3px;
                    border: none;
                    cursor: pointer;
                    transition: .3s;

                    &.watch {
                        background: $c-green-theme;

                        &:hover {
                            background-color: $c-success;
                            color: $c-white;
                        }
                    }

                    &.add {
                        background: $c-white;

                        &:hover {
                            background-color: $c-b;
                        }
                    }
                }
                .btn-favourite {
                    border: none;
                    cursor: pointer;
                    transition: all .3s;
                    margin: 0 20px;
                    font-size: 35px;
                    background: none;
                    color: $c-white;

                    &:hover {
                        color: $c-red;
                        transform: scale(1.2);
                    }
                }

                .btn_likes {
                    background: transparent;
                    border: none;
                    margin: 0 15px;
                    cursor: pointer;

                    svg {
                        width: 40px;
                        height: 40px;
                        fill: $c-white;
                        transition: all .3s;
                    }

                    &.like {
                        &:hover {
                            svg {
                                transform: scale(1.2);
                                fill: $c-green-theme;
                            }
                        }
                    }

                    &.dislike {
                        &:hover {
                            svg {
                                transform: scale(1.2);
                                fill: $c-error;
                            }
                        }
                    }
                }
            }
        }
    }
}
</style>